const { Storage } = require('@google-cloud/storage');
const storage = new Storage();

exports.serveFile = async (req, res) => {
  try {
    const bucketName = req.query.bucket;
    const filePath = req.query.file;
    
    if (!bucketName || !filePath) {
      res.status(400).send('Bucket and file path must be specified in query parameters.');
      return;
    }

    const bucket = storage.bucket(bucketName);
    const file = bucket.file(filePath);

    file.exists((err, exists) => {
      if (err) {
        res.status(500).send('Error checking file existence.');
        return;
      }
      
      if (!exists) {
        res.status(404).send('File not found.');
        return;
      }

      file.createReadStream()
        .on('error', (err) => {
          res.status(500).send('Error while reading the file.');
        })
        .pipe(res);
    });

  } catch (error) {
    res.status(500).send('Server error.');
  }
};